<?php
namespace Database\Seeders;
use App\Models\Campaign; use App\Models\CampaignCategory; use App\Models\Donation; use App\Models\Role; use App\Models\User; use Illuminate\Database\Seeder; use Illuminate\Support\Facades\Hash; use Illuminate\Support\Str;
class DatabaseSeeder extends Seeder { public function run(): void { $roles=collect([['Admin Yayasan','admin'],['Penggalang Dana','fundraiser'],['Donatur','donor']])->mapWithKeys(fn($r)=>[$r[1]=>Role::firstOrCreate(['slug'=>$r[1]],['name'=>$r[0],'description'=>'Role '.$r[0]])]); $admin=User::firstOrCreate(['email'=>'admin@sumselseduli.test'],['name'=>'Admin Yayasan','password'=>Hash::make('password'),'role_id'=>$roles['admin']->id,'email_verified_at'=>now()]); $fundraiser=User::firstOrCreate(['email'=>'fundraiser@sumselseduli.test'],['name'=>'Relawan Palembang','password'=>Hash::make('password'),'role_id'=>$roles['fundraiser']->id,'email_verified_at'=>now()]); $donor=User::firstOrCreate(['email'=>'donatur@sumselseduli.test'],['name'=>'Donatur Demo','password'=>Hash::make('password'),'role_id'=>$roles['donor']->id,'email_verified_at'=>now()]); $categories=collect(['Pendidikan','Kesehatan','Bencana Alam','Sosial'])->map(fn($name)=>CampaignCategory::firstOrCreate(['slug'=>Str::slug($name)],['name'=>$name,'description'=>'Campaign kategori '.$name])); $titles=['Bantu Seragam Sekolah Anak Banyuasin','Operasi Katarak Lansia Muara Enim','Bantuan Banjir Musi Rawas','Dapur Umum Warga Ogan Ilir','Beasiswa Santri Prabumulih','Renovasi Rumah Dhuafa Lahat','Ambulans Gratis Palembang','Paket Gizi Anak OKU Timur','Perlengkapan Sekolah Pagar Alam','Sumur Bersih Desa Empat Lawang']; foreach($titles as $i=>$title){ $campaign=Campaign::firstOrCreate(['slug'=>Str::slug($title)],['category_id'=>$categories[$i % $categories->count()]->id,'fundraiser_id'=>$fundraiser->id,'title'=>$title,'short_description'=>'Program sosial lokal Sumatera Selatan yang telah diverifikasi relawan yayasan.','story'=>'Yayasan Sosial Sumsel Peduli menggalang bantuan untuk kebutuhan nyata masyarakat Sumatera Selatan. Dana digunakan secara bertahap dan dilaporkan melalui fitur transparansi agar donatur dapat memantau manfaat donasinya.','target_amount'=>25000000 + ($i*3000000),'collected_amount'=>0,'used_amount'=>0,'status'=>$i < 8 ? 'active' : 'pending','verified_by'=>$i < 8 ? $admin->id : null,'verified_at'=>$i < 8 ? now() : null,'starts_at'=>now()->subDays(10),'ends_at'=>now()->addDays(45),'location'=>'Sumatera Selatan']); if($campaign->status==='active'){ $donation=Donation::create(['campaign_id'=>$campaign->id,'donor_id'=>$donor->id,'donor_name'=>$donor->name,'donor_email'=>$donor->email,'amount'=>500000 + ($i*50000),'message'=>'Semoga bermanfaat.','status'=>'verified','verified_by'=>$admin->id,'verified_at'=>now()]); $campaign->increment('collected_amount',$donation->amount); $campaign->updates()->create(['user_id'=>$fundraiser->id,'title'=>'Update lapangan awal','content'=>'Relawan telah melakukan asesmen kebutuhan penerima manfaat dan mengumpulkan dokumentasi pendukung.','published_at'=>now()]); $campaign->transparencyReports()->create(['user_id'=>$fundraiser->id,'title'=>'Pembelian kebutuhan tahap 1','description'=>'Dana digunakan untuk pengadaan bantuan prioritas sesuai hasil asesmen.','amount_used'=>100000,'usage_date'=>now()->subDays(2)]); } } } }
